/**
 * Britz Blythe Optimized JS Bundle
 * Includes: main, cart, product, search, theme-toggle, back-to-top, scroll-animations
 */

/* --- scroll-animations.js --- */
document.addEventListener('DOMContentLoaded', () => { const e = { threshold: .1, rootMargin: '0px 0px -50px 0px' }, t = new IntersectionObserver(e => { e.forEach(e => { if (e.isIntersecting) { e.target.classList.add('appeared'); t.unobserve(e.target) } }) }, e); document.querySelectorAll('.fade-in-up').forEach(e => t.observe(e)) });

/* --- lazy-images.js --- */
document.addEventListener('DOMContentLoaded', () => {
    const lazyImages = document.querySelectorAll('.lazy-image');
    lazyImages.forEach(img => {
        if (img.complete) { img.classList.add('loaded'); }
        else { img.addEventListener('load', () => { img.classList.add('loaded'); }, { once: true }); }
    });
});

/* --- back-to-top.js --- */
document.addEventListener('DOMContentLoaded', () => { const e = document.getElementById('backToTop'); if (!e) return; window.addEventListener('scroll', () => { if (window.scrollY > 400) e.classList.add('is-visible'); else e.classList.remove('is-visible') }); e.addEventListener('click', () => { window.scrollTo({ top: 0, behavior: 'smooth' }) }) });

/* --- theme-toggle.js --- */
document.addEventListener('DOMContentLoaded', function () {
    const h = document.documentElement, b = document.body;
    const s = localStorage.getItem('britz-theme');
    const p = window.matchMedia('(prefers-color-scheme: dark)').matches;
    let c = s || (p ? 'dark' : 'light');

    h.dataset.theme = c;

    const updateBtn = (btn, theme) => { btn.innerHTML = theme === 'dark' ? '☀️' : '🌙'; };

    const toggleTheme = (btn) => {
        const n = h.dataset.theme === 'dark' ? 'light' : 'dark';
        h.dataset.theme = n;
        localStorage.setItem('britz-theme', n);
        updateBtn(btn, n);
        btn.classList.add('rotating');
        setTimeout(() => btn.classList.remove('rotating'), 500);
        b.style.backdropFilter = 'blur(20px)';
        setTimeout(() => { b.style.backdropFilter = ''; }, 500);
    };

    let t = document.querySelector('[data-theme-toggle]');
    if (!t) {
        const nav = document.querySelector('.nav-actions');
        if (nav) {
            t = document.createElement('button');
            t.classList.add('theme-toggle-btn');
            t.dataset.themeToggle = '';
            t.style.cssText = 'background:var(--glass-bg);border:1px solid var(--glass-border);border-radius:50%;width:44px;height:44px;cursor:pointer;font-size:1.2rem;backdrop-filter:var(--blur);display:flex;align-items:center;justify-content:center;';
            nav.appendChild(t);
        }
    }

    if (t) {
        updateBtn(t, c);
        t.addEventListener('click', () => toggleTheme(t));
    }
});

console.log('Britz Blythe Optimized JS Bundle Loaded.');

/**
 * DEV TIP: For local development, it is better to keep files separate and 
 * use a PHP conditional to only serve the bundle in production:
 * 
 * <?php if (IS_PRODUCTION): ?>
 *    <script src="bundle.min.js"></script>
 * <?php else: ?>
 *    <script src="main.js"></script>...
 * <?php endif; ?>
 */